<?php include __DIR__.'/includes/header.php';$rows=db()->query("SELECT * FROM events WHERE active=1 ORDER BY event_date ASC")->fetchAll();?><section class="section"><h1>Events</h1><div class="grid"><?php if(!$rows): ?><div class="card"><h3>Events coming soon</h3></div><?php endif; ?><?php foreach($rows as $r): ?><div class="card"><span class="badge"><?=h($r['event_type'])?></span><h3><?=h($r['title'])?></h3><p><?=h($r['description'])?></p></div><?php endforeach; ?></div></section><?php include __DIR__.'/includes/footer.php'; ?>